689	func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
690		if eventSink != nil {
691			defer eventSink.Close() //nolint:errcheck
692		}
693		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
694		rcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
695			Assignee:          "ddx",
696			Harness:           spec.Harness,
697			Model:             spec.Model,
698			Provider:          spec.Provider,
699			ModelRef:          spec.ModelRef,
700			Profile:           agent.NormalizeRoutingProfile(spec.Profile),
701			Effort:            spec.Effort,
702			OpaquePassthrough: spec.OpaquePassthrough,
703		})
704	
705		var worker *agent.ExecuteBeadWorker
706		var costCap *policyescalation.CostCapTracker
707		if m.BeadWorkerFactory != nil {
708			worker = m.BeadWorkerFactory(store)
709		} else {
710			// Build an executor that calls agent.ExecuteBead in-process, then
711			// submits the result to the project's land coordinator. The
712			// coordinator (a single goroutine per projectRoot) serializes all
713			// target-ref writes for this project — this is the server-side
714			// implementation of the human-PR landing model. See ddx-8746d8a6
715			// for the rationale. Prior to this rewrite, runWorker never called
716			// LandBeadResult at all, so commits produced by server-managed
717			// workers were silently lost (ddx-e14efc58).
718			coordinator := m.LandCoordinators.Get(projectRoot)
719	
720			// singleTierAttempt runs one execution at a specific harness/model.
721			// The caller controls MinPower per rung; this helper keeps the
722			// profile stable and only advances the power floor.
723			singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
724				gitOps := &agent.RealGitOps{}
725				attemptProvider := spec.Provider
726				if resolvedProvider != "" {
727					attemptProvider = resolvedProvider
728				}
729				attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
730					Harness:           resolvedHarness,
731					Model:             resolvedModel,
732					Provider:          attemptProvider,
733					ModelRef:          spec.ModelRef,
734					Profile:           rcfg.Profile(),
735					Effort:            spec.Effort,
736					MinPower:          requestedMinPower,
737					OpaquePassthrough: spec.OpaquePassthrough,
738				})
739				beadStore := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
740				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
741					BeadEvents: beadStore,
742					BeadCancel: beadStore,
743				}, gitOps)
744				if err != nil && res == nil {
745					return agent.ExecuteBeadReport{}, err
746				}
747				// Preserve operator-cancel results as-is; the worker has already
748				// classified them (preserved / operator_cancel / preserved_needs_review)
749				// and overriding here would lose the cancel signal.
750				operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
751				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
752					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
753						err = landErr
754					}
755				} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
756					res.Outcome = "no-changes"
757					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
758				} else if res != nil && res.ExitCode != 0 && !operatorCancel {
759					res.Outcome = "preserved"
760					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
761				}
762				// Safety net: commit any leftover evidence files that Land()
763				// did not pick up (e.g. HEAD was detached, or no land ran).
764				if res != nil && res.AttemptID != "" {
765					_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
766				}
767				if err != nil {
768					return agent.ExecuteBeadReport{}, err
769				}
770				return agent.ExecuteBeadReport{
771					BeadID:             res.BeadID,
772					AttemptID:          res.AttemptID,
773					WorkerID:           res.WorkerID,
774					Harness:            res.Harness,
775					Provider:           res.Provider,
776					Model:              res.Model,
777					ActualPower:        res.ActualPower,
778					Status:             res.Status,
779					Detail:             res.Detail,
780					SessionID:          res.SessionID,
781					BaseRev:            res.BaseRev,
782					ResultRev:          res.ResultRev,
783					PreserveRef:        res.PreserveRef,
784					NoChangesRationale: res.NoChangesRationale,
785					CostUSD:            res.CostUSD,
786					DurationMS:         int64(res.DurationMS),
787				}, nil
788			}
789	
790			// Cost-cap state for this worker run. Subscription / local providers do
791			// not contribute (see escalation.CountsTowardCostCap).
792			// TODO(ddx-785d02f7): expose maxCostUSD as a worker spec field
793			// once the spec config knob lands.
794			var ladderOnce sync.Once
795			var ladder *tierescalation.Ladder
796			loadLadder := func() *tierescalation.Ladder {
797				ladderOnce.Do(func() {
798					ladder = tierescalation.NewLadder(nil)
799					if svc, svcErr := agent.NewServiceFromWorkDir(projectRoot); svcErr == nil {
800						modelFilter := agentlib.ModelFilter{}
801						if harness := rcfg.Harness(); harness != "" {
802							modelFilter.Harness = harness
803						}
804						modelCtx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
805						defer cancel()
806						if models, listErr := svc.ListModels(modelCtx, modelFilter); listErr == nil {
807							ladder = tierescalation.NewLadder(models)
808						}
809					}
810				})
811				return ladder
812			}
813			costCap = policyescalation.NewCostCapTracker(policyescalation.DefaultMaxCostUSD, func(harnessName string) bool {
814				svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
815				if svcErr != nil {
816					return true
817				}
818				infos, err := svc.ListHarnesses(context.Background())
819				if err != nil {
820					return true
821				}
822				for _, h := range infos {
823					if h.Name == harnessName {
824						return policyescalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
825					}
826				}
827				return true
828			})
829			accumulateBilledCost := func(report agent.ExecuteBeadReport) {
830				costCap.Add(report.Harness, report.CostUSD)
831			}
832			costCapTripped := func() (agent.ExecuteBeadReport, bool) {
833				if _, tripped := costCap.Tripped(); !tripped {
834					return agent.ExecuteBeadReport{}, false
835				}
836				spent := costCap.Spent()
837				return agent.ExecuteBeadReport{
838					Status: agent.ExecuteBeadStatusExecutionFailed,
839					Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, policyescalation.DefaultMaxCostUSD),
840				}, true
841			}
842			attemptWithCostCap := func(ctx context.Context, beadID string, requestedMinPower int) (agent.ExecuteBeadReport, error) {
843				if cappedReport, capped := costCapTripped(); capped {
844					cappedReport.BeadID = beadID
845					return cappedReport, nil
846				}
847				report, err := singleTierAttempt(ctx, beadID, requestedMinPower, spec.Harness, spec.Provider, spec.Model)
848				if err == nil {
849					accumulateBilledCost(report)
850					if cappedReport, capped := costCapTripped(); capped {
851						cappedReport.BeadID = beadID
852						return cappedReport, nil
853					}
854				}
855				return report, err
856			}
857	
858			executor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
859				attempts := make([]policyescalation.TierAttemptRecord, 0, 3)
860				recordAttempt := func(report agent.ExecuteBeadReport) {
861					if report.Tier == "" && report.Harness == "" && report.Model == "" && report.ProbeResult == "" && report.CostUSD == 0 && report.DurationMS == 0 {
862						return
863					}
864					attempts = append(attempts, policyescalation.TierAttemptRecord{
865						Tier:       report.Tier,
866						Harness:    report.Harness,
867						Model:      report.Model,
868						Status:     report.Status,
869						CostUSD:    report.CostUSD,
870						DurationMS: report.DurationMS,
871					})
872					appendTierAttemptEvent(store, beadID, report, "ddx", time.Now().UTC())
873				}
874				report, err := runEscalatingSingleTierAttempts(ctx, rcfg.MinPower(), loadLadder(), func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
875					return attemptWithCostCap(ctx, beadID, requestedMinPower)
876				}, recordAttempt)
877				if len(attempts) > 0 {
878					winningTier := ""
879					if report.Status == agent.ExecuteBeadStatusSuccess && report.Tier != "" {
880						winningTier = report.Tier
881					}
882					_ = policyescalation.AppendEscalationSummaryEvent(store, beadID, "ddx", attempts, winningTier, time.Now().UTC())
883				}
884				return report, err
885			})
