40	func runEscalatingSingleTierAttempts(
41		ctx context.Context,
42		initialMinPower int,
43		ladder escalationFloorFinder,
44		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
45		recordAttempt func(agent.ExecuteBeadReport),
46	) (agent.ExecuteBeadReport, error) {
47		minPower := initialMinPower
48		for {
49			report, err := attempt(ctx, minPower)
50			if recordAttempt != nil && report.BeadID != "" {
51				recordAttempt(report)
52			}
53			if err != nil {
54				return report, err
55			}
56			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
57				return report, nil
58			}
59			basis := minPower
60			if report.ActualPower > 0 {
61				basis = report.ActualPower
62			}
63			nextPower, nextErr := nextEscalationFloor(ladder, basis)
64			if nextErr != nil {
65				return report, nil
66			}
67			minPower = nextPower
68		}
69	}
